previewCss:
.darma-loader-darma-custom-750 {
  color: var(--loader-color, #22c55e);
  --loader-secondary-color: var(--loader-secondary-color, #86efac);
  --loader-bg: var(--loader-bg, #ffffff);
width: 50px;
height: 12px;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: 12px 12px;
position: relative;
}
.darma-loader-darma-custom-750:before {
content: "";
position: absolute;
height: 12px;
aspect-ratio: 1;
border-radius: 50%;
background: currentColor;
inset: 0;
margin: auto;
animation: darma-loader-darma-custom-750-l25-1 1s, darma-loader-darma-custom-750-l25-2 0.5s;
animation-timing-function: cubic-bezier(.45, 0, .55, 1);
animation-iteration-count: infinite;
}
@keyframes darma-loader-darma-custom-750-l25-1 {
100% {transform:translate(0.12px)}
}
@keyframes darma-loader-darma-custom-750-l25-2 {
100% {inset:-0.15px 0 0;}
}

